import { describe, expect, it } from "vitest";
import { paginate } from "../src/paginate.js";

describe("paginate", () => {
  it("returns a full page of `size` rows when enough remain", () => {
    // 23 rows, page 1, size 10 -> label says "showing 1-10", so 10 rows must render.
    const all = Array.from({ length: 23 }, (_, i) => i + 1);
    const { items, total } = paginate(all, 1, 10);
    expect(items).toHaveLength(10);
    expect(total).toBe(23);
  });
});

